select da.*, de.name depot_name from jsh_depot_allocation da
left join jsh_depot de on da.depot_id=de.id and ifnull(de.delete_Flag,'0') !='1'
where 1=1


    and da.allocation like #{bindAllocation}


    and da.type = #{type}


    and da.depot_id = #{depotId}

and ifnull(da.delete_flag,'0') !='1'
order by id desc

    limit #{offset},#{rows}

select count(da.id) from jsh_depot_allocation da
left join jsh_depot de on da.depot_id=de.id and ifnull(de.delete_Flag,'0') !='1'
where 1=1


    and da.allocation like #{bindAllocation}



    and da.type like #{bindType}


    and da.depot_id = #{depotId}

and ifnull(da.delete_flag,'0') !='1'

